mapper.select:
/* SmsMgmtMapper.getSmsTemplateList */ SELECT TEMPLATE_ID AS templateId ,TEMPLATE_NM AS templateNm ,MGMT_ORGN_ID AS mgmtOrgnId ,FN_GET_ORGNM(MGMT_ORGN_ID) AS mgmtOrgnNm ,WORK_TYPE AS workType ,FN_GET_CODENM('CMN0069', WORK_TYPE) AS workTypeNm ,CALLBACK ,FN_GET_CODENM('CMN0070', CALLBACK) AS callbackNm ,EXPIRE_HOUR AS expireHour ,SUBJECT ,TEXT ,RETRY ,REGST_ID AS regstId ,FN_GET_USRNM(REGST_ID) AS regstNm ,TO_CHAR(REGST_DTTM, 'YYYYMMDDHH24MISS') AS regstDttm ,RVISN_ID AS rvisnId ,FN_GET_USRNM(RVISN_ID) AS rvisnNm ,TO_CHAR(RVISN_DTTM, 'YYYYMMDDHH24MISS') AS rvisnDttm ,K_TEMPLATE_CODE AS kTemplateCode FROM MSP_SMS_TEMPLATE_MST
AND MGMT_ORGN_ID = #{searchOrgnId}
AND WORK_TYPE = #{searchWorkType}
AND UPPER(TEMPLATE_NM) LIKE '%' || UPPER(#{searchTemplateNm}) || '%'
ORDER BY TEMPLATE_ID

mapper.update:
/* SmsMgmtMapper.updateSmsTemplate */
UPDATE MSP_SMS_TEMPLATE_MST
SET    TEMPLATE_NM = #{templateNm}
	  ,MGMT_ORGN_ID = #{mgmtOrgnId}
	  ,WORK_TYPE = #{workType}
	  ,MSG_TYPE = #{msgType}
	  ,CALLBACK = #{callback}
	  ,EXPIRE_HOUR = #{expireHour}
	  ,SUBJECT = #{subject}
	  ,RETRY = NVL(#{retry}, 0)
	  ,TEXT = #{text}
	  ,RVISN_ID = #{sessionUserId}
	  ,RVISN_DTTM = SYSDATE
	  ,K_TEMPLATE_CODE = #{kTemplateCode}
WHERE  TEMPLATE_ID = #{templateId}

mapper.select:
/* SmsMgmtMapper.getTemplateId */
SELECT NVL(MAX(TEMPLATE_ID), 0) + 1 AS newTemplateId
FROM   MSP_SMS_TEMPLATE_MST

/* SmsMgmtMapper.checkTemplateId */
SELECT DECODE(COUNT(1), 0, 'N', 'Y') AS existFlag
FROM   MSP_SMS_TEMPLATE_MST
WHERE  TEMPLATE_ID = #{newTemplateId}

mapper.insert:
