	,#{text}
	,#{expireHour}
	,#{subject}
	,#{workType}
	,NVL(#{retry}, 0)
	,#{sessionUserId}
	,SYSDATE
	,#{sessionUserId}
	,SYSDATE
	,#{kTemplateCode}
)

mapper.select:
/* SmsMgmtMapper.getSmsSendList */
SELECT A.MSG_ID , A.SUBMIT_TIME , A.SCHEDULE_TIME , A.SUBJECT , A.RCPT_DATA , A.CALLBACK_NUM , A.MESSAGE , A.MSG_TYPE , A.RESERVED01 , A.RESERVED02 , A.RESERVED03 , A.K_MESSAGE , A.K_TMPLCODE , A.K_SENDERKEY , B.CD_DSC AS RESULT_NM , C.CD_DSC AS KKO_RESULT_NM FROM AM2X_SUBMIT_LOG A , CMN_GRP_CD_MST B , CMN_GRP_CD_MST C WHERE 1=1 AND TRIM(A.RESULT) = B.CD_VAL(+) AND B.GRP_ID(+) = 'CMN0283' AND TRIM(A.KKO_RESULT) = C.CD_VAL(+) AND C.GRP_ID(+) = 'CMN0283' AND A.SCHEDULE_TIME BETWEEN #{searchStartDate} AND #{searchEndDate}
AND A.SUBJECT LIKE '%' || #{searchValue} || '%'
AND A.RCPT_DATA = #{searchValue}
AND A.RESERVED02 = #{searchValue}
ORDER BY A.SCHEDULE_TIME DESC

mapper.insert:
/* SmsMgmtMapper.insertSmsSendMst */
INSERT INTO MSP_SMS_RESEND_MST (
	 SEND_SEQ			/* 일련번호	*/
	,TEMPLATE_ID		/* SMS Template ID */
	,MSG_ID				/* SMS일련번호 */
	,SEND_REQ_DTTM		/* 발송요청일시 */
	,REGST_ID			/* 등록자ID */
	,REGST_DTTM			/* 등록일시 */
	,RVISN_ID			/* 수정자ID */
	,RVISN_DTTM			/* 수정일시 */
)
VALUES (
	 SMS_RESEND_SEQ.NEXTVAL
	,#{templateId}
	,#{msgId}
	,#{sendReqDttm}
	,#{reqId}
	,SYSDATE
	,#{reqId}
	,SYSDATE
)

mapper.select:
/* SmsMgmtMapper.getTemplateText */
SELECT text AS templateText
	  ,subject AS templateSubject
FROM   MSP_SMS_TEMPLATE_MST
WHERE  TEMPLATE_ID = #{templateId}

/* SmsMgmtMapper.checkMsgResult */
SELECT COUNT(1) AS CNT
FROM   MSG_RESULT
WHERE  MSEQ = #{mseq}

/* SmsMgmtMapper.getMspSelectList */
SELECT 'MSP' AS custDiv , A.SUB_LINK_NAME AS custNm , A.SUB_LINK_NAME AS custNmMsk , A.SUBSCRIBER_NO AS mobileNo , A.SUBSCRIBER_NO AS mobileNoMsk , A.LST_COM_ACTV_DATE AS openDt , B.LST_RATE_CD AS rateCd , FN_GET_RATENM(B.LST_RATE_CD) AS rateNm , FN_GET_CODENM('RCP9004', B.REQ_BUY_TYPE) AS buyTypeNm , NVL(C.AGR_YN, 'N') AS marketingCd , (SELECT LISTAGG(Y.RATE_NM, '|') WITHIN GROUP(ORDER BY X.SOC) FROM MSP_JUO_FEATURE_INFO X , MSP_RATE_MST Y WHERE X.SOC = Y.RATE_CD AND X.CONTRACT_NUM = A.CONTRACT_NUM AND X.SERVICE_TYPE <> 'P' AND X.APP_END_DATE = '99991231000000'
AND Y.RATE_NM LIKE '%' || #{searchValue} || '%'
GROUP BY X.CONTRACT_NUM ) AS addService , A.CONTRACT_NUM AS contractNum FROM MSP_JUO_SUB_INFO A , MSP_REQUEST_DTL B , MSP_MRKT_AGR_MGMT C WHERE A.SUB_STATUS <> 'C' AND A.CONTRACT_NUM = B.CONTRACT_NUM(+) AND A.CONTRACT_NUM = C.CONTRACT_NUM(+) AND C.END_DTTM(+) = '99991231235959'
AND A.LST_COM_ACTV_DATE BETWEEN #{searchFromDt} AND #{searchToDt}
AND UPPER(A.SUB_LINK_NAME) LIKE '%' || UPPER(#{searchValue}) || '%'
AND A.SUBSCRIBER_NO = #{searchValue}
AND B.REQ_BUY_TYPE = #{searchBuyType}
AND A.OPEN_AGNT_CD = #{searchOrgnId}
AND B.LST_RATE_CD = #{searchRateCd}
AND NVL(C.AGR_YN, 'N') = #{searchMarketing}
ORDER BY A.LST_COM_ACTV_DATE

/* SmsMgmtMapper.getMcpSelectList */
SELECT 'MCP' AS custDiv , A.NAME AS custNm , A.NAME AS custNmMsk , A.MOBILE_NO AS mobileNo , A.MOBILE_NO AS mobileNoMsk , TO_CHAR(A.SYS_RDATE, 'YYYYMMDD') AS sysRdate , A.EMAIL_RCV_YN AS emailAgr , A.SMS_RCV_YN AS smsAgr , A.USERID AS portalId FROM MCP_USER@DL_MCP A WHERE A.STATUS <> '3' AND A.AUTH_CODE = 'USER_ROLE'
AND A.SYS_RDATE BETWEEN TO_DATE(#{searchFromDt}||'000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{searchToDt}||'235959', 'YYYYMMDDHH24MISS')
AND UPPER(A.NAME) LIKE '%' || UPPER(#{searchValue}) || '%'
AND A.MOBILE_NO = #{searchValue}
AND (A.EMAIL_RCV_YN = #{searchMarketing} OR A.SMS_RCV_YN = #{searchMarketing})
AND A.EMAIL_RCV_YN = #{searchMarketing} AND A.SMS_RCV_YN = #{searchMarketing}
ORDER BY A.NAME

/* SmsMgmtMapper.getReqSelectList */
SELECT DISTINCT 'REQ' AS custDiv , TO_CHAR(A.REQ_IN_DAY, 'YYYYMMDD') AS reqInDay , B.CSTMR_NAME AS custNm , B.CSTMR_NAME AS custNmMsk , NVL(B.CSTMR_MOBILE_FN || B.CSTMR_MOBILE_MN || B.CSTMR_MOBILE_RN, B.CSTMR_TEL_FN || B.CSTMR_TEL_MN || B.CSTMR_TEL_RN) AS mobileNo , NVL(B.CSTMR_MOBILE_FN || B.CSTMR_MOBILE_MN || B.CSTMR_MOBILE_RN, B.CSTMR_TEL_FN || B.CSTMR_TEL_MN || B.CSTMR_TEL_RN) AS mobileNoMsk , D.CD_DSC AS reqStateNm FROM MCP_REQUEST@DL_MCP A , MCP_REQUEST_CSTMR@DL_MCP B , MCP_REQUEST_SALEINFO@DL_MCP C , CMN_GRP_CD_MST D WHERE A.REQUEST_KEY = B.REQUEST_KEY AND A.REQUEST_KEY = C.REQUEST_KEY AND A.PSTATE = '00' AND A.REQUEST_STATE_CODE = '00' AND A.REQUEST_STATE_CODE = D.CD_VAL AND D.GRP_ID = 'RCP0006'
AND A.REQ_IN_DAY BETWEEN TO_DATE(#{searchFromDt}||'000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{searchToDt}||'235959', 'YYYYMMDDHH24MISS')
AND A.CNTPNT_SHOP_ID = #{searchOrgnId}
AND UPPER(B.CSTMR_NAME) LIKE '%' || UPPER(#{searchValue}) || '%'
AND NVL(B.CSTMR_MOBILE_FN || B.CSTMR_MOBILE_MN || B.CSTMR_MOBILE_RN, B.CSTMR_TEL_FN || B.CSTMR_TEL_MN || B.CSTMR_TEL_RN) = #{searchValue}
ORDER BY 2

/* SmsMgmtMapper.getContractNum */

SELECT MAX(CONTRACT_NUM) KEEP(DENSE_RANK FIRST ORDER BY LST_COM_ACTV_DATE DESC) AS contractNum
FROM   MSP_JUO_SUB_INFO
WHERE  SUBSCRIBER_NO = #{mobileNo}
AND    SUB_STATUS <>  'C'

/* ====== smsMgmtMapper.smsSendPhoneGrpList =========*/ SELECT A.GRP_ID --그룹코드 , A.GRP_NM --그룹명 , A.STRT_DT --시작일자 , A.END_DT --종료일자 , A.USE_YN --사용여부 , A.REGST_ID , A.REGST_DTTM , A.RVISN_ID , A.RVISN_DTTM , (SELECT COUNT(*) FROM MSP_SMS_PHONE_GRP_DTL WHERE GRP_ID = A.GRP_ID) AS CNT FROM MSP_SMS_PHONE_GRP_MST A WHERE 1=1
AND A.USE_YN = #{useYn} AND TO_CHAR(SYSDATE,'YYYYMMDD') BETWEEN A.STRT_DT AND A.END_DT
ORDER BY A.REGST_DTTM

