mapper.select:
/* smsMgmtMapper.msgSmsListMsgNo */
SELECT MSG_NO.NEXTVAL AS MSG_NO
FROM   DUAL

/* smsMgmtMapper.getMsgSmsSendList */ SELECT MSG_NO AS MSG_NO /* 문자NO */ , MSG_TYPE AS MSG_TYPE /* 1:SMS 2:SMS URL 3:MMS 4:MMS URL */ , SUBJECT AS SUBJECT /* 제목 */ , SEND_CNT AS SEND_CNT /* 전송건수 */ , TO_CHAR(TO_DATE(REQUEST_TIME,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') AS REQUEST_TIME /* 예약전송시간 */ , REGST_ID AS REGST_ID /* 등록자 */ , TO_CHAR(REGST_TIME, 'YYYY-MM-DD HH24:MI:SS') AS REGST_TIME /* 등록시간 */ , MSG_SMS_TYPE AS MSG_SMS_TYPE /* 발송타입 */ , DECODE(MSG_SMS_TYPE, 'S' , '템플릿', 'MMS') AS MSG_SMS_TYPE_NM /* S:같은내용 D:다른내용 */ , MSG_TMP_ID AS MSG_TMP_ID /* 템플릿ID */ , MSG_USG_YN AS MSG_USG_YN /* 사용여부YN */ , RESULT_YN AS RESULT_YN /* 처리결과YN */ , DECODE(RESULT_YN,'Y','완료','N','대기','E','오류',RESULT_YN) AS RESULT_YN_NM /* 처리결과 */ , RESULT_CODE AS RESULT_CODE /* RESULTCODE */ , KAKAO_YN AS KAKAO_YN /* 카카오여부 */ FROM MSG_SMS_LIST WHERE MSG_USG_YN = 'Y'
AND TO_CHAR(TO_DATE(REQUEST_TIME,'YYYYMMDDHH24MISS'),'YYYYMMDD') BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND SUBJECT LIKE '%' || #{searchName} || '%'
AND REGST_ID = #{searchName}
AND RESULT_YN = #{resultYn}
ORDER BY REQUEST_TIME DESC

		/* smsMgmtMapper.isMsgSmsDeleteAuth */
		SELECT  DECODE(COUNT(*), 1, 'Y', 'N') RESULT
		FROM    MSG_SMS_LIST
		WHERE   MSG_NO = #{msgNo}
		AND     REGST_ID = #{sessionUserId}
        AND     RESULT_YN = 'N'
		AND     MSG_USG_YN = 'Y'

mapper.update:
/* smsMgmtMapper.deleteMsgSmsList */
UPDATE	MSG_SMS_LIST
SET		MSG_USG_YN = 'N'										/* 사용여부 	*/		
	,  	RVISN_ID = #{sessionUserId} 							/* 수정자이름 	*/
	,  	RVISN_DTTM = SYSDATE			   						/* 수정날짜 	*/
	,   SEND_CNT = (SELECT COUNT(*) FROM MSG_SMS_SEND_LIST WHERE MSG_NO = #{msgNo})						
WHERE	MSG_NO = #{msgNo}
AND		REGST_ID = #{sessionUserId}
AND		RESULT_YN = 'N'
AND     MSG_USG_YN = 'Y'

