mapper.select:
/* smsMgmtMapper.getMsgSendMsgType */
SELECT MSG_TYPE AS MSG_TMP_ID
FROM   MSP_SMS_TEMPLATE_MST 
WHERE  TEMPLATE_ID = #{msgTmpId}

