mapper.update:
 /* smsMgmtMapper.getSmsTmpCallBack */
 UPDATE MSG_SMS_SEND_LIST A
	SET A.MSG_SEND_CTN = (SELECT CALLBACK FROM  MSP_SMS_TEMPLATE_MST B WHERE TEMPLATE_ID = #{msgTmpId, jdbcType=VARCHAR})
	   ,A.MSG_TITLE = (SELECT SUBJECT FROM MSP_SMS_TEMPLATE_MST B WHERE TEMPLATE_ID = #{msgTmpId, jdbcType=VARCHAR})
	   ,A.MSG_TEXT = (SELECT TEXT FROM  MSP_SMS_TEMPLATE_MST B WHERE TEMPLATE_ID = #{msgTmpId, jdbcType=VARCHAR})
	WHERE A.MSG_NO = #{msgNo, jdbcType=VARCHAR}

mapper.insert:
SELECT SMS_SEQ.NEXTVAL AS mseq ,DECODE(NVL(#{sendType}, 'I'), 'I', TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), #{requestTime}) AS requestTime FROM DUAL
/* SmsMgmtMapper.insertMsgTmpQueue */ INSERT INTO MSG_QUEUE ( MSEQ /* Sequence */ ,MSG_TYPE /* 1:SMS 2:SMS URL 3:MMS 4:MMS URL */ ,DSTADDR /* 수신자 번호 */ ,CALLBACK /* 발신자 번호 */ ,SUBJECT /* 제목 */ ,TEXT /* 전송메시지 */ ,EXPIRETIME /* 유효시간 */ ,REQUEST_TIME /* 발송요청시간 */ ,OPT_ID /* SMS TEMPLATE ID */ ,TEXT2 /* 카카오 실패 시 대체발송 메세지 */ ,K_TEMPLATE_CODE /* 카카오 알림톡 템플릿 코드 */ ,K_NEXT_TYPE /* 카카오 실패 시 대체발송 메세지 타입 7:SMS, 8:LMS, 9:MMS */ ,SENDER_KEY /* 카카오 발신프로필키 */ ) SELECT #{mseq}
,'6' ,MSG_TYPE
,#{mobileNo} ,CALLBACK ,NVL( #{subject}, SUBJECT ) ,NVL( #{text}, TEXT ) ,EXPIRE_HOUR * 60 * 60 ,TO_DATE(#{requestTime}, 'YYYYMMDDHH24MISS') ,TEMPLATE_ID ,NVL( #{text2}, TEXT ) ,NVL( K_TEMPLATE_CODE, '') ,NVL( #{kNextType}, '') ,NVL( #{senderKey}, '') FROM MSP_SMS_TEMPLATE_MST WHERE TEMPLATE_ID = #{templateId}

/* SmsMgmtMapper.insertMsgQueue */
INSERT INTO MSG_QUEUE 
(
	MSEQ

	    ,MSG_TYPE


	    ,DSTADDR


	    ,CALLBACK


	    ,SUBJECT


	    ,STAT


	    ,TEXT_TYPE


	    ,TEXT


	    ,EXPIRETIME


	    ,REQUEST_TIME


	    ,OPT_ID


	    ,EXT_COL0


	    ,TEXT2


	    ,K_TEMPLATE_CODE


	    ,K_NEXT_TYPE


	    ,SENDER_KEY


	    ,FILECNT


	    ,FILELOC1


	    ,FILELOC2


	    ,FILELOC3


	    ,FILELOC4


	    ,FILELOC5

) VALUES (
	SMS_SEQ.NEXTVAL

	    ,#{msgType}


	    ,#{dstaddr}


	    ,#{callback}


	    ,#{subject}


	    ,#{stat}


	    ,#{textType}


	    ,#{text}


	    ,#{expiretime}


		,TO_DATE(#{requestTime}, 'YYYYMMDDHH24MISS')


	    ,#{optId}


	    ,#{extCol0}


	    ,#{text2}


	    ,#{kTemplateCode}


	    ,#{kNextType}


	    ,#{senderKey}


	    ,#{fileCnt}


	    ,#{fileLoc1}


	    ,#{fileLoc2}


	    ,#{fileLoc3}


	    ,#{fileLoc4}


	    ,#{fileLoc5}

)

/* SmsMgmtMapper.insertKtMsgQueue */
INSERT INTO AM2X_SUBMIT 
(
	MSG_ID

	    ,SUBJECT


	    ,MSG_TYPE


	    ,MSG_TYPE_SECOND


	    ,MSG_TYPE_THIRD

	    ,SCHEDULE_TIME
	    ,SUBMIT_TIME

	    ,MESSAGE


	    ,CALLBACK_NUM


	    ,RCPT_DATA


	    ,FILE_COUNT


	    ,FILE_NAME1


	    ,FILE_NAME2


	    ,FILE_NAME3


	    ,CDR_ID


	    ,FAIL_SEND


	    ,K_TMPLCODE


	    ,K_MESSAGE


	    ,K_BUTTON


	    ,K_ADFLAG


	    ,K_SENDERKEY


	    ,R_MESSAGEBASEID


	    ,R_BODY


	    ,R_BUTTON


	    ,R_HEADER


	    ,R_FOOTER


	    ,R_COPYALLOWED


	    ,R_QUERYID


	    ,RESERVED01


	    ,RESERVED02


	    ,RESERVED03


	    ,KISA_ORIG_CODE


	    ,R_AGENCYID


	    ,R_AGENCYKEY


	    ,R_BRANDKEY


	    ,R_CDR_ID


) VALUES (
	AM2X_SUBMIT_SEQ.NEXTVAL

	    ,#{subject}



		    ,#{msgType}


		    ,DECODE(#{msgType}, '3', '2', #{msgType})



	    ,#{msgTypeSecond}


	    ,#{msgTypeThird}


		 ,#{scheduleTime} 
		,TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') 


		 ,#{submitTime} 
		,TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') 


	    ,#{message}


	    ,#{callbackNum}


	    ,REPLACE(#{rcptData},CHR(10),'')


	    ,#{fileCount}


	    ,#{fileName1}


	    ,#{fileName2}


	    ,#{fileName3}


	    ,#{cdrId}


	    ,#{failSend}


	    ,#{kTmplcode}


	    ,#{kMessage}


	    ,#{kButton}


	    ,#{kAdflag}


	    ,#{kSenderkey}


	    ,#{rMessagebaseid}


	    ,#{rBody}


	    ,#{rButton}


	    ,#{rHeader}


	    ,#{rFooter}


	    ,#{rCopyallowed}


	    ,#{rQueryid}


	    ,#{reserved01}


	    ,#{reserved02}


	    ,#{reserved03}


	    ,#{kisaOrigCode}


	    ,#{rAgencyid}


	    ,#{rAgencykey}


	    ,#{rBrandkey}


	    ,#{rCdrId}

)

SELECT AM2X_SUBMIT_SEQ.NEXTVAL AS msgId ,DECODE(NVL(#{sendType}, 'I'), 'I', TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'), #{scheduleTime}) AS scheduleTime FROM DUAL
/* SmsMgmtMapper.insertKtMsgTmpQueue */ INSERT INTO AM2X_SUBMIT ( MSG_ID /* Sequence */ ,MSG_TYPE /* 1=SMS 2=LMS 3=MMS 6=A_KAKAO */ ,FAIL_SEND /* 실패시 재 발송 여부(카카오 실패일 경우 발송)*/ ,RCPT_DATA /* 수신자 번호 */ ,CALLBACK_NUM /* 발신자 번호 */ ,SUBJECT /* 제목 */ ,MESSAGE /* 전송메시지 */ ,SCHEDULE_TIME /* 발송요청시간 */ ,SUBMIT_TIME /* 등록시간 */ ,RESERVED01 /* MSP */ ,RESERVED02 /* SMS TEMPLATE ID */ ,RESERVED03 /* 발송자,발송화면 */ ,K_MESSAGE /* 카카오 실패 시 대체발송 메세지 */ ,K_TMPLCODE /* 카카오 알림톡 템플릿 코드 */ ,MSG_TYPE_SECOND /* 카카오 실패 시 대체발송 메세지 타입 1=SMS 2=LMS 3=MMS */ ,K_SENDERKEY /* 카카오 발신프로필키 */ ) SELECT #{msgId}
, '6', 'Y' ,DECODE(MSG_TYPE, '3', '2', MSG_TYPE), 'N'
,#{rcptData} ,CALLBACK ,NVL( #{subject}, SUBJECT ) ,NVL( #{message}, TEXT ) ,#{scheduleTime} ,TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') ,#{reserved01} ,#{reserved02} ,#{reserved03}
,NVL( #{kMessage}, TEXT ) , ''
,NVL( K_TEMPLATE_CODE, '') ,NVL( #{msgTypeSecond}, 0) ,NVL( #{kSenderkey}, '') FROM MSP_SMS_TEMPLATE_MST WHERE TEMPLATE_ID = #{templateId}

mapper.update:
/* SmsMgmtMapper.updateSmsSendMst */
UPDATE  MSP_SMS_SEND_MST
SET     SEND_CNT = SEND_CNT + 1
       ,MSEQ = #{msgId}
       ,SEND_REQ_DTTM = #{scheduleTime}
       ,RVISN_ID = #{userId}
       ,RVISN_DTTM = SYSDATE
WHERE   SEND_SEQ = #{sendSeq}
AND 		KT_SMS_YN = 'Y'

mapper.select:
/* SmsMgmtMapper.checkKtMsgResult */
SELECT COUNT(1) AS CNT
FROM   AM2X_SUBMIT_LOG
WHERE  MSG_ID = #{msgId}

mapper.delete:
/* SmsMgmtMapper.deleteKtMsgQueue */
DELETE
FROM   AM2X_SUBMIT
WHERE  MSG_ID = #{msgId}

/* SmsMgmtMapper.deleteKtSmsSendMst */
DELETE
FROM   MSP_SMS_SEND_MST
WHERE  SEND_SEQ = #{sendSeq}
AND 	   KT_SMS_YN = 'Y'
